import pandas as pd

def filter_csv(input_csv, output_csv, num_list):
    
    df = pd.read_csv(input_csv, skiprows=7, sep=';')
    df.columns = df.columns.str.strip()
    filtered_df = df[df['#[ms]'].isin(num_list)]
    filtered_df.to_csv(output_csv, index=False)
    print(f"Filtered data saved to {output_csv}")

